function Cart({ cart, onRemove, onCheckout, onBack }) {
  const total = cart.reduce((sum, item) => sum + parseFloat(item.price), 0);

  return (
    <div className="cart">
      <h2>Your Cart</h2>
      <p>{cart.length} item{cart.length !== 1 ? 's' : ''}</p>
      {cart.map((item, i) => (
        <div key={i} className="cart-card">
          <span className="cart-icon-box">{item.icon}</span>
          <div className="cart-info">
            <div className="cart-name">{item.realName || item.name}</div>
            <div className="cart-qty">{item.qty}</div>
          </div>
          <div className="cart-item-price">£{item.price}</div>
          <button className="remove-btn" onClick={() => onRemove(i)}>×</button>
        </div>
      ))}
      <div className="cart-total-row">
        <span>Total</span>
        <strong>£{total.toFixed(2)}</strong>
      </div>
      <button className="main-btn" onClick={onCheckout}>Proceed to payment →</button>
      <button className="back-btn" onClick={onBack}>← Continue shopping</button>
    </div>
  );
}

export default Cart;
